# MomentO Backend System Repair Script
import base64, os, subprocess

# Base64 encoded critical backend files
FILES = {
    "server.js": "",
    "package.json": "",
    "routes/auth.routes.js": "",
    "routes/booking.routes.js": "",
    "routes/review.routes.js": "",
    "routes/event.routes.js": "",
    "routes/admin.routes.js": "",
    "models/Booking.js": "",
    "models/User.js": "",
    "middleware/auth.middleware.js": ""
}

def repair():
    print("🚀 Starting MomentO Backend Repair...")
    
    # 1. Create directories
    for f_path in FILES.keys():
        dir_name = os.path.dirname(f_path)
        if dir_name and not os.path.exists(dir_name):
            os.makedirs(dir_name, exist_ok=True)
            print(f"📁 Created directory: {dir_name}")

    # 2. Write files
    for f_path, encoded_content in FILES.items():
        print(f"📄 Restoring: {f_path}...")
        encoded_content = encoded_content.strip()
        padding = 4 - (len(encoded_content) % 4)
        if padding != 4:
            encoded_content += "=" * padding
        with open(f_path, "wb") as f:
            f.write(base64.b64decode(encoded_content))
            
    # 3. Check .env
    if not os.path.exists(".env"):
        print("⚠️  Warning: .env file missing. Using defaults.")
        with open(".env", "w") as f:
            f.write("PORT=5000\nMONGO_URI=mongodb+srv://padmasrinamala3_db_user:padhu2004@cluster0.beq18z3.mongodb.net/momento?retryWrites=true&w=majority&appName=Cluster0\nJWT_SECRET=momento_super_secret_key_2025\n")

    # 4. Install Dependencies
    print("📦 Installing dependencies...")
    try:
        subprocess.run(["npm", "install"], check=True, shell=True)
    except Exception as e:
        print(f"❌ npm install failed: {e}")

    # 5. Restart with PM2
    print("🔄 Restarting service...")
    try:
        subprocess.run(["pm2", "delete", "backend"], shell=True)
        subprocess.run(["pm2", "start", "server.js", "--name", "backend"], check=True, shell=True)
        print("✅ PM2 service restarted!")
    except:
        print("⚠️  PM2 fail. Trying node server.js...")
        subprocess.Popen(["node", "server.js"], shell=True)

    print("\n✨ Repair Complete! Check http://16.170.239.192/api/health in 10 seconds.")

if __name__ == "__main__":
    repair()
